import{_ as t,o as n,c as o,ag as s}from"./chunks/framework.BBBcTwIo.js";const g=JSON.parse('{"title":"Generate the demo scene","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/demo-scene.md","filePath":"how-to/demo-scene.md"}'),r={name:"how-to/demo-scene.md"};function a(i,e,l,c,d,h){return n(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="generate-the-demo-scene" tabindex="-1">Generate the demo scene <a class="header-anchor" href="#generate-the-demo-scene" aria-label="Permalink to &quot;Generate the demo scene&quot;">​</a></h1><p><strong>Goal:</strong> Create a ready-made Unity scene that fires sample events so you can verify <strong>SUB</strong> and <strong>INVOKE</strong> rows without writing code.</p><p><strong>Prerequisites:</strong> Event Monitor Editor extension installed (menu item present).</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>In the Unity menu, choose <strong>Tools → Event Monitor → Generate Demo Scene</strong>.</li><li>Confirm the dialog if prompted. The scene is saved under <code>Assets/</code> (name may match your package version, for example <code>EventMonitor_Demo.unity</code>).</li><li>Open <strong>Window → Event Monitor</strong> and enable <strong>Record</strong>.</li><li>Enter <strong>Play Mode</strong>.</li><li>Click UI buttons (labels show event names), or run <strong>Run sample sequence</strong> / <strong>Random event burst</strong> if present.</li></ol><p>You should see <strong>SUB</strong> lines when listeners attach and <strong>INVOKE</strong> lines when buttons trigger events. A small <strong>HUD</strong> mirrors the last actions for quick visual confirmation.</p><h2 id="what-the-demo-includes" tabindex="-1">What the demo includes <a class="header-anchor" href="#what-the-demo-includes" aria-label="Permalink to &quot;What the demo includes&quot;">​</a></h2><p>Typical contents (exact names may vary by version):</p><ul><li><strong>Canvas</strong> with labeled controls (player, game state, enemy samples).</li><li><strong>Promo / demo buses</strong> — MonoBehaviours exposing C# events.</li><li><strong>Listeners</strong> — extra subscribers so the <strong>Subscribers</strong> graph is non-trivial.</li><li><strong>ReflectionScanner</strong> — fallback subscription discovery alongside ILPP.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../guide/quick-start.html">Quick Start</a></li><li><a href="./../concepts/ilpp-vs-reflection-scanner.html">ILPP vs ReflectionScanner</a></li></ul>',11)])])}const u=t(r,[["render",a]]);export{g as __pageData,u as default};
